VALUES
  ('bookkeeper-moex-01229', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '根據國際會計準則第41號「農業」，下列何者並非該準則列舉之生物資產？', '["綿羊", "乳牛", "棉花", "人造森林之林木"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01230', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '根據國際會計準則第2 號「存貨」之規範中，對於性質與用途類似之所有存貨，應採用相同之成本公式。 惟下列何者為該準則不允許之成本計算公式？', '["成本個別認定法", "先進先出法", "加權平均成本法", "後進先出法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01231', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '丙公司於X1年1月1日購買成本$120,000，估計可使用8年，無殘值之設備一部，公司採用直線法提列 折舊。X3年12月31日設備之使用價值$72,000，淨公允價值為$70,000，X5年12月31日使用價值$36,000， 淨公允價值為$39,000，X6年12月31日使用價值$35,000，淨公允價值為$31,000。請問X6年12月31 日資產負債表之設備餘額為：', '["$26,000", "$30,000", "$31,000", "$35,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01232', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', 'X4年10月1日丁公司以現金買回流通在外普通股1,000股為庫藏股票，買回成本每股$15，而11月15日 以每股$17出售半數庫藏股票，12月16日以每股$12出售剩餘之庫藏股票。請問X4年12月16日出售庫 藏股票時，丁公司應以「資本公積－庫藏股票交易」（借記或貸記）與金額進行如下之正確記錄：', '["借記：1,000", "借記：1,500", "貸記：1,000", "貸記：1,500"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01233', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司採用曆年制會計年度，在X4年12月31日資產負債表中，該公司會計部門正斟酌一項報表表達問 題。該公司積欠之負債中，$200,000將於X5年2月16日到期，甲公司打算與銀行完成再融資協議，將 $200,000負債延長至X6年予以清償，而此協議已於X5年1月31日完成雙方之再融資合約，董事會並 於X5年3月31日通過X4年度之財務報表並宣布。請問此$200,000負債於X4年12月31日的資產負債 表應如何表達？', '["流動負債", "長期負債", "$100,000為流動負債，$100,000為長期負債", "$200,000轉為股東權益項目"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01234', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '戊公司根據國際會計準則第16號「不動產、廠房及設備」，並於X4年12月31日對於設備進行重估價 模式，當時設備之帳面金額為$300,000，原始成本$500,000，累計折舊$200,000，而設備之公允價值為 $360,000。請問戊公司於X4年12月31日採用重估模式後，設備之帳面金額為：', '["$200,000", "$300,000", "$360,000", "$500,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01235', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '下列何項資產係屬投資性不動產適用範圍？', '["土地開發公司自用之土地", "人壽保險公司持有為賺取租金或資本增值之不動產", "電子公司持有為擴建廠房使用", "建設公司持有準備於營業過程中出售之不動產"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01236', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '請問下列何者為財務報表的外部使用者？', '["公司經理人", "公司股東", "公司員工", "公司的董事"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01237', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '乙公司於X3年10月15日簽發一張90天期，5%，面額$300,000的票據一張，藉此票據以清償即將到期 的帳款。若一年以360天計算，此票據之到期日應為：', '["X3年12月31日", "X4年1月13日", "X4年1月15日", "X4年1月31日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01238', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '大甲公司過去向小乙公司購入一項工具專利權，$1,000,000，目前該專利權帳面價值為$600,000。然而， 公司本年度發現中丙公司仿製公司專利，經訴訟後獲得勝訴，訴訟費用合計$200,000。重新評估該專利權 可使用兩年預計產生$450,000之淨現金流量折現值，另外經估價該專利權之淨公允價值為$400,000。請問 下列敘述何者正確？', '["維護專利權勝訴的費用$200,000，應列為當年度費用", "專利權餘額應採用現金流量折現值加本年度專利權訴訟維護費用$470,000列為專利權成本", "專利權應採用帳面價值$600,000攤銷", "本年度專利權應用可收回現值價值與公允價值較低者列帳"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01239', 'bookkeeper', 'bookkeeper-moex-104-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', 'X2年12月31日，乙公司已發行之普通股10,000股，每股面額$10，同時，累積與完全參加特別股2,000 股，每股面額$25，股利率5%。X3年度乙公司宣告並發放現金股利$15,000，X4年並未宣告現金股利。 請問當乙公司採用曆年制會計年度，X4年12月31日「應付現金股利」之餘額為：', '["$0", "$2,500", "$5,000", "$15,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "d4bb38bfd4ad", "answer_pdf_sha1": "0663b26b8679", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01240', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法之規定，下列關於納稅義務人之敘述，何者正確？ 共有財產設有管理人者，由使用人負納稅義務 公同共有財產未設管理人者，共有人各按其應有部分負納稅義務 分別共有財產未設管理人者，以全體共有人為納稅義務人 營利事業因合併而消滅時，其在合併前之應納稅捐，應由合併後存續或另立之營利事業負繳納之義務', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01241', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法之規定，營利事業因故被補徵稅款，繳納期限至民國104年7月14日（星期二）截止， 因不服欲申請復查，最遲應於何日前提出？ 104年8月13日  104年8月12日  104年8月14日  104年9月13日', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01242', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行稅捐稽徵法第48條之1的規定，納稅義務人在未經檢舉、調查前，自動向稅捐稽徵機關補報並補繳 所漏稅款者，下列敘述何者正確？ 加計利息免罰  加計利息減半處罰  免加計利息免罰  免加計利息減半處罰', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01243', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '張無忌104年度之房屋稅繳款書，經臺北市稅捐稽徵處中正分處於104年4月20日送達。該房屋稅核定應 納稅額為10萬元，繳納期間為104年5月1日至5月31日（星期日），若張無忌於104年6月3日繳納 該稅款，依現行稅捐稽徵法規定，應加徵滯納金若干？ 0元  1千元  2千元  1萬5千元', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
